// Procesar datos de cada unidad con detección mejorada de motor
const item = $input.item.json;

// Extraer datos relevantes
const unidad = item.nm || 'Desconocido';
const pos = item.pos || {};
const params = pos.p || {};

// Timestamp actual
const timestamp = new Date().toISOString();
const ultimaActualizacion = pos.t ? new Date(pos.t * 1000).toISOString() : timestamp;

// DETECCIÓN DE ESTADO DEL MOTOR POR INFERENCIA
let motorEstado = 'Desconocido';
const velocidad = pos.s || 0;
const ultimoReporte = pos.t || 0;
const tiempoDesdeReporte = Date.now() / 1000 - ultimoReporte; // en segundos

// Método 1: Revisar parámetros directos si existen
if (params.hasOwnProperty('pwr') || params.hasOwnProperty('power')) {
  motorEstado = (params.pwr || params.power) > 0 ? 'Encendido' : 'Apagado';
}
else if (params.hasOwnProperty('ign') || params.hasOwnProperty('ignition')) {
  motorEstado = (params.ign || params.ignition) === 1 ? 'Encendido' : 'Apagado';
}
else if (params.hasOwnProperty('engine_state')) {
  motorEstado = params.engine_state === 1 ? 'Encendido' : 'Apagado';
}
// Método 2: INFERENCIA por velocidad y comportamiento
else {
  if (velocidad > 5) {
    motorEstado = 'Encendido';
  } else if (velocidad > 0 && velocidad <= 5) {
    motorEstado = 'Encendido';
  } else if (velocidad === 0 && tiempoDesdeReporte < 1800) {
    motorEstado = 'Apagado';
  } else {
    motorEstado = 'Apagado';
  }
}

// Determinar evento basado en velocidad y estado
let evento = 'Normal';
if (pos.s >= 5) {
  evento = 'En movimiento';
} else if (motorEstado === 'Encendido' && pos.s < 5) {
  evento = 'Ralentí';
} else if (motorEstado === 'Apagado') {
  evento = 'Detenido';
} else {
  evento = 'Estacionado';
}

return {
  timestamp: timestamp,
  unidad: unidad,
  lat: pos.y || 0,
  lng: pos.x || 0,
  velocidad_kmh: pos.s || 0,
  motor_estado: motorEstado,
  combustible_litros: params.fuel_level || params.fuel || 0,
  odometro_km: params.mileage || params.total_mileage || 0,
  evento: evento,
  ultima_actualizacion: ultimaActualizacion
};

// Extract and transform geofence data from Wialon to Google Sheets format
const item = $input.item.json;
const items = [];

// Get the geofences from the response
const geofences = Array.isArray(item) ? item : (item.zones || []);

if (geofences && geofences.length > 0) {
  for (const geofence of geofences) {
    // Determine geofence type based on name
    let tipo = 'otro';
    const nombreLower = (geofence.n || '').toLowerCase();

    if (nombreLower.includes('taller') || nombreLower.includes('faw') || nombreLower.includes('elam')) {
      tipo = 'taller';
    } else if (nombreLower.includes('caseta') || nombreLower.includes('peaje')) {
      tipo = 'caseta';
    } else if (nombreLower.includes('puerto')) {
      tipo = 'puerto';
    } else if (nombreLower.includes('cliente') || nombreLower.includes('entrega')) {
      tipo = 'cliente';
    }

    // Extract center point
    let lat = null;
    let lng = null;
    let ubicacion = '';

    if (geofence.b && geofence.b.cen_x && geofence.b.cen_y) {
      lat = geofence.b.cen_y;
      lng = geofence.b.cen_x;
    } else if (geofence.p && Array.isArray(geofence.p) && geofence.p.length > 0) {
      let sumX = 0, sumY = 0;
      for (const point of geofence.p) {
        sumX += point.x;
        sumY += point.y;
      }
      lat = sumY / geofence.p.length;
      lng = sumX / geofence.p.length;
    }

    if (geofence.d && geofence.d.address) {
      ubicacion = geofence.d.address;
    } else {
      ubicacion = geofence.n || 'Sin ubicación';
    }

    // Status mappings
    let status_entrada, status_salida, actividad_entrada, actividad_salida, prioridad_alerta;

    switch(tipo) {
      case 'taller':
        status_entrada = 'En Taller';
        status_salida = 'Disponible';
        actividad_entrada = 'Mantenimiento';
        actividad_salida = 'Esperando asignación';
        prioridad_alerta = 'media';
        break;
      case 'puerto':
        status_entrada = 'En Puerto';
        status_salida = 'En Ruta';
        actividad_entrada = 'Carga/Descarga';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'alta';
        break;
      case 'caseta':
        status_entrada = 'En Ruta';
        status_salida = 'En Ruta';
        actividad_entrada = 'Tránsito autopista';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'baja';
        break;
      case 'cliente':
        status_entrada = 'Descargando';
        status_salida = 'En Ruta';
        actividad_entrada = 'Entrega en curso';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'alta';
        break;
      default:
        status_entrada = 'En Ruta';
        status_salida = 'En Ruta';
        actividad_entrada = 'Tránsito';
        actividad_salida = 'Tránsito';
        prioridad_alerta = 'baja';
    }

    items.push({
      nombre: geofence.n || 'Sin nombre',
      tipo: tipo,
      ubicacion: ubicacion,
      lat: lat,
      lng: lng,
      status_entrada: status_entrada,
      status_salida: status_salida,
      actividad_entrada: actividad_entrada,
      actividad_salida: actividad_salida,
      prioridad_alerta: prioridad_alerta,
      notas: geofence.d?.dscr || ''
    });
  }
}

return items.length > 0 ? items.map(item => ({json: item})) : [{json: {}}];
